class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        vector<int> res;
        long long prev = 0, curr = 0;
        for (int i = 0; i < num.size(); ++i) {
            curr = curr * 10 + (num[i] - '0');
            if (curr > INT_MAX) return {};
            if (i > 0 && prev == 0) {
                res.push_back(curr);
                prev = curr;
                curr = 0;
            } else if (curr == prev + res.back()) {
                res.push_back(curr);
                prev = curr;
                curr = 0;
            }
        }
        return res;
    }
};
```
